import{_ as d,o as e,c as o,ag as a}from"./chunks/framework.DTiDeF2Q.js";const b=JSON.parse('{"title":"اختصارات Chmod: مختصرات صلاحيات الملفات للشل | Dotfiles (AR)","titleTemplate":":title","description":"بسّط إدارة صلاحيات الملفات والمجلدات مع اختصارات chmod. مختصرات سريعة لأنماط الصلاحيات الشائعة مثل 755 و644 والمزيد.","frontmatter":{"title":"اختصارات Chmod: مختصرات صلاحيات الملفات للشل","description":"بسّط إدارة صلاحيات الملفات والمجلدات مع اختصارات chmod. مختصرات سريعة لأنماط الصلاحيات الشائعة مثل 755 و644 والمزيد.","lang":"ar-SA","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"اختصارات Chmod: مختصرات صلاحيات الملفات للشل preview","canonical":"/ar/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"اختصارات Chmod: مختصرات صلاحيات الملفات للشل","pageType":"docs","schemaType":"WebPage","metaTitle":"اختصارات Chmod | Dotfiles","permalink":"/ar/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod aliases, file permissions, shell shortcuts, dotfiles, unix permissions"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"اختصارات Chmod | Dotfiles"},{"name":"twitter:description","content":"بسّط إدارة صلاحيات الملفات والمجلدات مع اختصارات chmod."},{"name":"og:title","content":"اختصارات Chmod | Dotfiles"},{"name":"og:description","content":"بسّط إدارة صلاحيات الملفات والمجلدات مع اختصارات chmod."},{"name":"og:image:alt","content":"Dotfiles - مصمم ببساطة ليناسب حياتك مع الشل"},{"name":"og:locale","content":"ar_SA"}]},"headers":[],"relativePath":"ar/aliases/chmod/index.md","filePath":"ar/aliases/chmod/index.md","lastUpdated":1773010926000}'),r={name:"ar/aliases/chmod/index.md"};function c(h,t,i,s,n,l){return e(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="اختصارات-chmod" tabindex="-1">اختصارات Chmod <a class="header-anchor" href="#اختصارات-chmod" aria-label="Permalink to &quot;اختصارات Chmod&quot;">​</a></h1><p>مختصرات لإدارة صلاحيات الملفات والمجلدات.</p><h2 id="نظرة-عامة" tabindex="-1">نظرة عامة <a class="header-anchor" href="#نظرة-عامة" aria-label="Permalink to &quot;نظرة عامة&quot;">​</a></h2><p>توفر اختصارات chmod طريقة مبسطة لإدارة صلاحيات الملفات والمجلدات من سطر الأوامر. بدلاً من تذكر رموز الصلاحيات الرقمية، استخدم اختصارات بديهية مثل <code>chmod_755</code> أو <code>chmod_u+x</code> لتعيين وضع الوصول الذي تحتاجه بسرعة.</p><p>هذه الاختصارات معرّفة في <code>chmod.aliases.sh</code> ويتم تحميلها تلقائيًا بواسطة chezmoi.</p><h2 id="المرجع" tabindex="-1">المرجع <a class="header-anchor" href="#المرجع" aria-label="Permalink to &quot;المرجع&quot;">​</a></h2><h3 id="اختصارات-الصلاحيات-الشائعة" tabindex="-1">اختصارات الصلاحيات الشائعة <a class="header-anchor" href="#اختصارات-الصلاحيات-الشائعة" aria-label="Permalink to &quot;اختصارات الصلاحيات الشائعة&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الصلاحيات</th><th>الوصف</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>لا صلاحيات لأي أحد</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>قراءة فقط للمالك</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>قراءة فقط للجميع</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>قراءة/كتابة للمالك</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>قراءة/كتابة للمالك، قراءة فقط للآخرين</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>قراءة/كتابة للجميع</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>كامل للمالك، قراءة/تنفيذ للآخرين</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>كامل للمالك، قراءة/كتابة للمجموعة</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>صلاحيات كاملة للجميع</td></tr></tbody></table><h3 id="اختصارات-صلاحيات-المالك" tabindex="-1">اختصارات صلاحيات المالك <a class="header-anchor" href="#اختصارات-صلاحيات-المالك" aria-label="Permalink to &quot;اختصارات صلاحيات المالك&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>إضافة صلاحية التنفيذ للمالك</td></tr><tr><td><code>chmod_u-x</code></td><td>إزالة صلاحية التنفيذ للمالك</td></tr><tr><td><code>chmod_u+w</code></td><td>إضافة صلاحية الكتابة للمالك</td></tr><tr><td><code>chmod_u-w</code></td><td>إزالة صلاحية الكتابة للمالك</td></tr><tr><td><code>chmod_u+r</code></td><td>إضافة صلاحية القراءة للمالك</td></tr><tr><td><code>chmod_u-r</code></td><td>إزالة صلاحية القراءة للمالك</td></tr></tbody></table><h3 id="اختصارات-صلاحيات-المجموعة" tabindex="-1">اختصارات صلاحيات المجموعة <a class="header-anchor" href="#اختصارات-صلاحيات-المجموعة" aria-label="Permalink to &quot;اختصارات صلاحيات المجموعة&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>إضافة صلاحية التنفيذ للمجموعة</td></tr><tr><td><code>chmod_g-x</code></td><td>إزالة صلاحية التنفيذ للمجموعة</td></tr><tr><td><code>chmod_g+w</code></td><td>إضافة صلاحية الكتابة للمجموعة</td></tr><tr><td><code>chmod_g-w</code></td><td>إزالة صلاحية الكتابة للمجموعة</td></tr><tr><td><code>chmod_g+r</code></td><td>إضافة صلاحية القراءة للمجموعة</td></tr><tr><td><code>chmod_g-r</code></td><td>إزالة صلاحية القراءة للمجموعة</td></tr></tbody></table><h3 id="اختصارات-صلاحيات-الآخرين" tabindex="-1">اختصارات صلاحيات الآخرين <a class="header-anchor" href="#اختصارات-صلاحيات-الآخرين" aria-label="Permalink to &quot;اختصارات صلاحيات الآخرين&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>إضافة صلاحية التنفيذ للآخرين</td></tr><tr><td><code>chmod_o-x</code></td><td>إزالة صلاحية التنفيذ للآخرين</td></tr><tr><td><code>chmod_o+w</code></td><td>إضافة صلاحية الكتابة للآخرين</td></tr><tr><td><code>chmod_o-w</code></td><td>إزالة صلاحية الكتابة للآخرين</td></tr><tr><td><code>chmod_o+r</code></td><td>إضافة صلاحية القراءة للآخرين</td></tr><tr><td><code>chmod_o-r</code></td><td>إزالة صلاحية القراءة للآخرين</td></tr></tbody></table><h3 id="اختصارات-نوع-الملف" tabindex="-1">اختصارات نوع الملف <a class="header-anchor" href="#اختصارات-نوع-الملف" aria-label="Permalink to &quot;اختصارات نوع الملف&quot;">​</a></h3><table tabindex="0"><thead><tr><th>الاختصار</th><th>الوصف</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>تعيين صلاحيات جميع المجلدات إلى <code>rwxr-xr-x</code></td></tr><tr><td><code>chmod_644f</code></td><td>تعيين صلاحيات جميع الملفات إلى <code>rw-r--r--</code></td></tr></tbody></table><h3 id="دالة-الصلاحيات-التكرارية" tabindex="-1">دالة الصلاحيات التكرارية <a class="header-anchor" href="#دالة-الصلاحيات-التكرارية" aria-label="Permalink to &quot;دالة الصلاحيات التكرارية&quot;">​</a></h3><p>دالة <code>change_permission</code> تطبق الصلاحيات بشكل تكراري مع مطالبة تأكيد:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',19)])])}const p=d(r,[["render",c]]);export{b as __pageData,p as default};
